const body = $json.body ?? $json;
const connected = body.connected_account ?? {};
const signup = body.signup ?? {};
const code = body.code ?? signup.code;
const wabaId = body.waba_id ?? connected.waba_id;
const phoneNumberId = body.phone_number_id ?? connected.phone_number_id;

if (!code) throw new Error('code is required');
if (!wabaId) throw new Error('waba_id is required');
if (!phoneNumberId) throw new Error('phone_number_id is required');

return [{
  json: {
    code,
    waba_id: wabaId,
    phone_number_id: phoneNumberId,
    business_id: body.business_id ?? connected.business_id,
    business_token: connected.business_token,
    token_metadata: connected.token_metadata ?? {},
    connected_at: connected.connected_at ?? new Date().toISOString(),
    owner: connected.owner ?? {
      client: body.client,
      user_id: body.user_id,
      team_id: body.team_id,
      account_id: body.account_id,
    },
    status: connected.status ?? 'connected',
    state: body.state ?? signup.state,
    should_exchange: !connected.business_token,
  },
}];

const validate = $('Validate Payload').item.json;
const exchangeItems = $('HTTP Request: Exchange Code With Meta').isExecuted ? $('HTTP Request: Exchange Code With Meta').all() : [];
const exchange = exchangeItems[0]?.json ?? {};

return [{
  json: {
    ...validate,
    business_token: validate.business_token ?? exchange.access_token,
    token_metadata: {
      ...validate.token_metadata,
      token_type: validate.token_metadata?.token_type ?? exchange.token_type,
      expires_in: exchange.expires_in,
    },
    status: validate.status === 'subscribed' ? 'subscribed' : 'connected',
  },
}];
